"""
Format Translator Module
Converts various tool calling formats to OpenCode's standard JSON format.
Handles gorilla-style Python function calls, native tool formats, and more.
"""

import re
import json
from typing import Optional, Dict, Any, List
from .json_fixer import smart_json_parse, parse_partial_json


class FormatTranslator:
    """Translates various tool calling formats to standard OpenCode JSON"""

    def __init__(self):
        # Pattern to match Python function calls: tool_name(arg1="value", arg2="value")
        self.python_func_pattern = re.compile(
            r'(\w+)\s*\(([^)]*)\)',
            re.MULTILINE
        )

        # Common tool names to recognize (22 actual tools + 1 alias)
        self.known_tools = {
            'file_read', 'read_text',  # read_text is alias for file_read
            'file_write', 'file_edit', 'file_search', 'directory_list',
            'file_copy', 'file_move', 'file_delete', 'file_create', 'file_fill',
            'bash_execute', 'grep_search', 'git_operations', 'change_directory',
            'system_info', 'resource_request', 'process_manage',
            'web_search', 'web_fetch', 'code_analyze', 'package_check'
        }

    def translate(self, response: str) -> Optional[Dict[str, Any]]:
        """
        Translate any recognized format to OpenCode JSON format

        Args:
            response: Raw model response

        Returns:
            Dict with standard format or None if no tool call found
        """
        # Try each translator in order of specificity
        result = (
            self._try_json_format(response) or
            self._try_markdown_emphasis_format(response) or
            self._try_python_function_format(response) or
            self._try_gemma_tools_format(response) or
            self._try_simple_function_format(response)
        )

        return result

    def _try_json_format(self, response: str) -> Optional[Dict[str, Any]]:
        """Check if response is already in correct JSON format"""
        try:
            # First, try the correct format: {"type":"tool_call","name":"...","args":{...}}
            json_match = re.search(r'\{\s*"type"\s*:\s*"tool_call"[^}]*"args"\s*:\s*\{[^}]*\}\s*\}', response, re.DOTALL)
            if json_match:
                # Use smart parser to handle incomplete/malformed JSON
                parsed = smart_json_parse(json_match.group(0))
                if parsed and self._validate_json_format(parsed):
                    return parsed

            # Also accept shorthand format: {"type":"tool_name","args":{...}}
            # where type directly contains the tool name instead of "tool_call"
            json_match = re.search(r'\{\s*"type"\s*:\s*"(\w+)"\s*,\s*"args"\s*:\s*\{[^}]*\}\s*\}', response, re.DOTALL)
            if json_match:
                parsed = smart_json_parse(json_match.group(0))
                if parsed:
                    tool_name = parsed.get("type")
                    # Check if it's a known tool name
                    if tool_name in self.known_tools:
                        # Convert to standard format
                        return {
                            "type": "tool_call",
                            "name": tool_name,
                            "args": parsed.get("args", {})
                        }

            # FALLBACK: Try to parse any JSON-like structure with smart parser
            # This handles markdown blocks, incomplete JSON, etc.
            parsed = smart_json_parse(response)
            if parsed and isinstance(parsed, dict):
                # Check if it's a valid tool call structure
                if "name" in parsed and isinstance(parsed.get("name"), str):
                    # Could be {"name": "tool", "arguments": {...}} format
                    if parsed.get("name") in self.known_tools:
                        return {
                            "type": "tool_call",
                            "name": parsed["name"],
                            "args": parsed.get("arguments", parsed.get("args", {}))
                        }
                elif "type" in parsed and parsed.get("type") == "tool_call":
                    # Standard format
                    if self._validate_json_format(parsed):
                        return parsed
        except:
            pass
        return None

    def _try_markdown_emphasis_format(self, response: str) -> Optional[Dict[str, Any]]:
        """
        Translate markdown-style emphasis patterns to tool calls

        Some models use asterisks or other emphasis markers around tool names:
            ***file_read***
            **web_search**
            *file_search*

        Examples:
            "I'll use ***file_read*** to check the file"
            "Let me ***file_search*** for that pattern"
            "Using **web_search** to find information"
        """
        # Pattern: *** or ** or * around a known tool name
        for tool_name in self.known_tools:
            # Try different emphasis levels
            patterns = [
                rf'\*\*\*{tool_name}\*\*\*',  # ***tool***
                rf'\*\*{tool_name}\*\*',      # **tool**
                rf'\*{tool_name}\*',          # *tool*
                rf'`{tool_name}`',            # `tool` (backticks)
                rf'_{tool_name}_',            # _tool_ (underscores)
            ]

            for pattern in patterns:
                if re.search(pattern, response, re.IGNORECASE):
                    # Found emphasized tool name - extract arguments from nearby context
                    args = self._extract_args_from_context(response, tool_name)

                    return {
                        "type": "tool_call",
                        "name": tool_name,
                        "args": args
                    }

        return None

    def _extract_args_from_context(self, response: str, tool_name: str) -> Dict[str, Any]:
        """
        Extract arguments from text context around an emphasized tool name.

        Looks for common patterns like:
        - "read test.txt" → {"file_path": "test.txt"}
        - "search for *.py" → {"pattern": "*.py"}
        - "with pattern animal" → {"pattern": "animal"}
        """
        args = {}

        # Common argument patterns for different tools
        if tool_name in ['file_read', 'read_text', 'file_write', 'file_edit']:
            # Look for file path mentions
            # Patterns: "read FILE", "from FILE", "file FILE", "the FILE"
            file_patterns = [
                r'"([^"]+\.[\w]+)"',  # Quoted filename (priority)
                r'`([^`]+\.[\w]+)`',  # Backtick filename
                r'(?:read|from|file|edit|write|check|the)\s+([^\s,\.]+\.[\w]+)',  # filename.ext
                r'(?:path|file_path|filepath)[:\s]+([^\s,]+)',
                r'([^\s]+\.(?:txt|py|json|yaml|yml|md|conf|cfg|ini))',  # Common extensions
            ]
            for pat in file_patterns:
                match = re.search(pat, response, re.IGNORECASE)
                if match:
                    file_path = match.group(1).strip('"\'`')
                    args['file_path'] = file_path
                    break

        elif tool_name == 'file_search':
            # Look for pattern mentions
            pattern_patterns = [
                r'(?:pattern|search|find)[:\s]+"([^"]+)"',  # Quoted pattern
                r'(?:pattern|search)[:\s]+`([^`]+)`',  # Backtick pattern
                r'(?:for|pattern)[:\s]+([^\s,\.!]+)',  # After "for" or "pattern"
                r'([^\s]+\.[\w]+)',  # Filename pattern (e.g., Read2.txt, *.py)
            ]
            for pat in pattern_patterns:
                match = re.search(pat, response, re.IGNORECASE)
                if match:
                    pattern = match.group(1).strip('"\'`')
                    args['pattern'] = pattern
                    break

        elif tool_name in ['web_search', 'grep_search']:
            # Look for query/pattern
            query_patterns = [
                r'(?:query|search|find)[:\s]+"([^"]+)"',
                r'(?:for|about)[:\s]+([^\n.]+)',
            ]
            for pat in query_patterns:
                match = re.search(pat, response, re.IGNORECASE)
                if match:
                    query = match.group(1).strip()
                    if tool_name == 'web_search':
                        args['query'] = query
                    else:
                        args['pattern'] = query
                    break

        return args

    def _try_python_function_format(self, response: str) -> Optional[Dict[str, Any]]:
        """
        Translate Python function calls to JSON

        Examples:
            file_read(file_path="test.txt")
            web_search(query="animal facts")
            file_search(pattern="animal", path=".")
        """
        # Find all function calls in the response
        matches = self.python_func_pattern.findall(response)

        for func_name, args_str in matches:
            # Check if it's a known tool
            if func_name not in self.known_tools:
                continue

            # Parse the arguments
            args = self._parse_python_args(args_str)
            if args is not None:
                return {
                    "type": "tool_call",
                    "name": func_name,
                    "args": args
                }

        return None

    def _parse_python_args(self, args_str: str) -> Optional[Dict[str, Any]]:
        """
        Parse Python-style function arguments

        Examples:
            'file_path="test.txt"' -> {"file_path": "test.txt"}
            'pattern="*.py", path="."' -> {"pattern": "*.py", "path": "."}
            'query="animal facts"' -> {"query": "animal facts"}
        """
        if not args_str.strip():
            return {}

        args = {}

        # Pattern for key="value" or key='value'
        arg_pattern = re.compile(r'(\w+)\s*=\s*["\']([^"\']*)["\']')
        matches = arg_pattern.findall(args_str)

        if matches:
            for key, value in matches:
                # Filter out invalid/noise parameters
                # Skip nested function calls like action=web_search(...)
                # Skip JSON objects like args={...}
                if not self._is_valid_param(key, value):
                    continue
                args[key] = value
            return args if args else None

        # Try to handle positional args or other formats
        # This is a fallback - try to extract any quoted strings
        quoted_values = re.findall(r'["\']([^"\']+)["\']', args_str)
        if quoted_values and len(quoted_values) == 1:
            # Single argument - guess the parameter name based on tool
            return {"value": quoted_values[0]}

        return None

    def _is_valid_param(self, key: str, value: str) -> bool:
        """Check if parameter looks valid (filter out gorilla model noise)"""
        # Skip common noise parameters that models hallucinate
        noise_params = {
            'action', 'args', 'result', 'output', 'response',
            'content',  # Often confused with file_path or data
            'data', 'value', 'input', 'params', 'options',
            'callback', 'handler', 'function', 'method'
        }
        if key in noise_params:
            return False

        # Skip if value looks like a function call
        if '(' in value or ')' in value:
            return False

        # Skip if value looks like a path to nowhere (common hallucination)
        if value.startswith('/home/user/') and 'user' not in value.split('/')[3:4]:
            # Hallucinated paths often have /home/user/ instead of actual user
            return False

        return True

    def _try_gemma_tools_format(self, response: str) -> Optional[Dict[str, Any]]:
        """
        Translate Gemma-style tool format

        Example:
            <tool_call>{"name": "file_read", "arguments": {"file_path": "test.txt"}}</tool_call>
        """
        match = re.search(r'<tool_call>\s*(\{.*?\})\s*</tool_call>', response, re.DOTALL)
        if match:
            try:
                parsed = json.loads(match.group(1))
                # Enforce dict type check
                if not isinstance(parsed, dict):
                    return None
                # Convert gemma format to our format
                if "name" in parsed and "arguments" in parsed:
                    return {
                        "type": "tool_call",
                        "name": parsed["name"],
                        "args": parsed["arguments"]
                    }
            except:
                pass
        return None

    def _try_simple_function_format(self, response: str) -> Optional[Dict[str, Any]]:
        """
        Handle simple function mentions

        Example:
            "I'll use file_read to check the file"
            -> Extract file_read as tool name, prompt user for args
        """
        # Look for tool name mentions
        for tool_name in self.known_tools:
            if tool_name in response.lower():
                # Check if it looks like an intention to use the tool
                intention_words = ['use', 'call', 'execute', 'run', 'invoke']
                if any(word in response.lower() for word in intention_words):
                    # Found an intention - return with empty args
                    # (The system can prompt for missing args)
                    return {
                        "type": "tool_call",
                        "name": tool_name,
                        "args": {}
                    }

        return None

    def _validate_json_format(self, parsed: Dict[str, Any]) -> bool:
        """Validate that JSON has required fields"""
        return (
            isinstance(parsed, dict) and
            parsed.get("type") == "tool_call" and
            "name" in parsed and
            "args" in parsed
        )

    def get_translation_info(self, response: str) -> Dict[str, Any]:
        """
        Get detailed information about translation attempt

        Returns:
            {
                "detected_format": "python_function" | "json" | "gemma" | "none",
                "tool_call": {...} or None,
                "confidence": 0.0-1.0,
                "original": original response snippet
            }
        """
        info = {
            "detected_format": "none",
            "tool_call": None,
            "confidence": 0.0,
            "original": response[:200]
        }

        # Check each format
        if self._try_json_format(response):
            info["detected_format"] = "json"
            info["tool_call"] = self._try_json_format(response)
            info["confidence"] = 1.0
        elif self._try_python_function_format(response):
            info["detected_format"] = "python_function"
            info["tool_call"] = self._try_python_function_format(response)
            info["confidence"] = 0.9
        elif self._try_gemma_tools_format(response):
            info["detected_format"] = "gemma_tools"
            info["tool_call"] = self._try_gemma_tools_format(response)
            info["confidence"] = 0.95
        elif self._try_simple_function_format(response):
            info["detected_format"] = "simple_mention"
            info["tool_call"] = self._try_simple_function_format(response)
            info["confidence"] = 0.5

        return info


def translate_tool_call(response: str) -> Optional[Dict[str, Any]]:
    """
    Convenience function for one-off translation

    Args:
        response: Raw model response

    Returns:
        Standard OpenCode tool call dict or None
    """
    translator = FormatTranslator()
    return translator.translate(response)


# Test cases
if __name__ == "__main__":
    translator = FormatTranslator()

    test_cases = [
        # Python function format (gorilla style)
        'file_read(file_path="test.txt")',
        'web_search(query="animal facts")',
        'file_search(pattern="*.py", path=".")',

        # Already correct JSON
        '{"type":"tool_call","name":"file_read","args":{"file_path":"test.txt"}}',

        # Gemma format
        '<tool_call>{"name": "file_read", "arguments": {"file_path": "test.txt"}}</tool_call>',

        # Complex gorilla output (from user's log)
        'file_search(pattern="animal",path="/home/user/Desktop/BackupOpencode/versions/v1.2/experiments/exp_20250930_114209",action=web_search(query="animal Read.txt"),args={"query":"animal facts"})',

        # Simple mention
        "I'll use file_read to check the configuration",
    ]

    print("Format Translator Test Cases\n")
    for i, test in enumerate(test_cases, 1):
        print(f"\n{i}. Input: {test[:80]}...")
        result = translator.translate(test)
        info = translator.get_translation_info(test)
        print(f"   Format: {info['detected_format']}")
        print(f"   Confidence: {info['confidence']}")
        if result:
            print(f"   Output: {json.dumps(result, indent=10)}")
        else:
            print(f"   Output: None")
